urlset:
{{ range .Pages }}
{{- if ne .Kind "taxonomy" }}

  {{ .Permalink }}{{ if not .Lastmod.IsZero }}
  {{ .Lastmod.Format "2006-01-02" }}{{ end }}
  {{- if .IsHome }}
  weekly
  1.0
  {{- else if .IsSection }}
  weekly
  0.8
  {{- else if .IsPage }}
  monthly
  0.7
  {{- else }}
  monthly
  0.5
  {{- end }}

{{- end }}
{{ end }}
